    @Test
    public void testDateOther() throws IOException
    {
        ObjectMapper mapper = newJsonMapper();
        DateFormat df = new SimpleDateFormat("yyyy-MM-dd'X'HH:mm:ss");
        mapper.setDateFormat(df);
        mapper.setTimeZone(TimeZone.getTimeZone("PST"));

